parameters.jsCode:
const records = items;
const now = new Date();
const VENTANA_HORAS = 2;

// Si por alguna razón la consulta viene vacía, permitimos responder por seguridad
if (!records || records.length <= 1) {
  return [{
    json: {
      can_respond: true,
      reason: "No se encontraron registros previos. Responder disponible.",
      hours_remaining: 0
    }
  }];
}

/**
 * 1. ORDENAMIENTO
 * Ordenamos para asegurar que el índice [0] sea siempre el más reciente
 */
const sortedRecords = [...records].sort((a, b) => 
  new Date(b.json.created_at) - new Date(a.json.created_at)
);

const lastRecord = sortedRecords[0].json;
const lastResponseDate = new Date(lastRecord.created_at);

// Cálculo de tiempo transcurrido
const diffMs = now - lastResponseDate;
const hoursElapsed = diffMs / (1000 * 60 * 60);
const minutesElapsed = diffMs / (1000 * 60);

// Cálculo de tiempo restante
const hoursRemaining = Math.max(0, VENTANA_HORAS - hoursElapsed);
const minutesRemaining = Math.max(0, (VENTANA_HORAS * 60) - minutesElapsed);

let canRespond = false;
let reason = "";

/**
 * 2. VALIDACIÓN DE VENTANA
 */
if (hoursElapsed >= VENTANA_HORAS) {
    canRespond = true;
    reason = `Permitido: Han pasado ${hoursElapsed.toFixed(2)}h.`;
} else {
    canRespond = false;
    reason = `Bloqueado: Re-contacto muy pronto. Faltan ${minutesRemaining.toFixed(0)} minutos para cumplir las 2h.`;
}

return [{
  json: {
    can_respond: canRespond,
    reason: reason,
    last_contact: lastRecord.created_at,
    hours_elapsed: hoursElapsed.toFixed(2),
    minutes_remaining: minutesRemaining.toFixed(0),
    total_messages_analizados: records.length
  }
}];

